@tagged("post_install", "-at_install")
class TestForecastPlanChatterTracking(ForecastTestCommon):
    """Test that chatter tracking works for important fields."""

    def test_state_change_tracked(self):
        """State changes should appear in chatter messages."""
        plan = self.create_forecast_plan()

        initial_msg_count = len(plan.message_ids)

        plan.action_confirm()

        self.assertEqual(len(plan.message_ids), initial_msg_count + 1)

    def test_user_change_tracked(self):
        """User changes should be tracked."""
        plan = self.create_forecast_plan()

        initial_msg_count = len(plan.message_ids)

        plan.write({"user_id": self.user_sales.id})

        self.assertGreater(len(plan.message_ids), initial_msg_count)
